import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { catchError, of, tap, switchMap } from 'rxjs';

import { AppStoreService } from '../../services/app-store.service';
import { AppDefinition } from '../../models/app-store.models';
import {
  getStatusSeverity,
  getStatusLabel,
} from '../../utils/status.utils';

import { ButtonModule } from 'primeng/button';
import { TableModule } from 'primeng/table';
import { TagModule } from 'primeng/tag';
import { CardModule } from 'primeng/card';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TooltipModule } from 'primeng/tooltip';

@Component({
  selector: 'app-app-admin-panel',
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    TableModule,
    TagModule,
    CardModule,
    ProgressSpinnerModule,
    TooltipModule,
  ],
  templateUrl: './app-admin-panel.component.html',
  styleUrls: ['./app-admin-panel.component.scss'],
})
export class AppAdminPanelComponent {
  private readonly appStoreService = inject(AppStoreService);

  // State Signals
  readonly statusFilter = signal<AppDefinition['status'] | 'ALL'>(
    'pendingReview',
  );
  readonly loading = signal(true);
  readonly error = signal<string | null>(null);
  private readonly refreshTrigger = signal(0);

  // Trigger data fetch when statusFilter or refreshTrigger changes
  private readonly apps$ = toObservable(
    computed(() => ({
      status: this.statusFilter(),
      refresh: this.refreshTrigger(),
    })),
  ).pipe(
    tap(() => {
      this.loading.set(true);
      this.error.set(null);
    }),
    switchMap(({ status }) => {
      const params = status === 'ALL' ? undefined : { status };
      return this.appStoreService.getApps(params).pipe(
        tap(() => {
          this.loading.set(false);
        }),
        catchError(() => {
          this.loading.set(false);
          this.error.set('Unable to load apps. Please try again.');
          return of([] as AppDefinition[]);
        }),
      );
    }),
  );

  readonly apps = toSignal(this.apps$, { initialValue: [] as AppDefinition[] });

  statusOptions: { label: string; value: AppDefinition['status'] | 'ALL' }[] = [
    { label: 'Draft', value: 'draft' },
    { label: 'Pending Review', value: 'pendingReview' },
    { label: 'Under Review', value: 'underReview' },
    { label: 'Changes Requested', value: 'changesRequested' },
    { label: 'Approved', value: 'approved' },
    { label: 'Rejected', value: 'rejected' },
    { label: 'Suspended', value: 'suspended' },
    { label: 'Withdrawn', value: 'withdrawn' },
    { label: 'All', value: 'ALL' },
  ];

  onStatusFilterChange(status: AppDefinition['status'] | 'ALL'): void {
    this.statusFilter.set(status);
  }

  approveApp(id: string): void {
    this.appStoreService.approveApp(id).subscribe(() => this.refreshApps());
  }

  rejectApp(id: string): void {
    this.appStoreService.rejectApp(id).subscribe(() => this.refreshApps());
  }

  suspendApp(id: string): void {
    this.appStoreService.suspendApp(id).subscribe(() => this.refreshApps());
  }

  private refreshApps(): void {
    this.refreshTrigger.update((n) => n + 1);
  }

  // Delegate to shared utility functions
  readonly statusSeverity = getStatusSeverity;
  readonly statusLabel = getStatusLabel;
}
